class Solution:
    def countSymmetricIntegers(self, low, high):
        def digits(x):
            d = []
            while x > 0:
                d.append(x % 10)
                x //= 10
            return d[::-1]
        count = 0
        for x in range(low, high + 1):
            d = digits(x)
            L = len(d)
            if L % 2:
                continue
            half = L // 2
            if sum(d[:half]) == sum(d[half:]):
                count += 1
        return count

