class Solution:
    def countSymmetricIntegers(self, low, high):
        count = 0
        for x in range(low, high + 1):
            st = str(x)
            L = len(st)
            if L % 2 != 0:
                continue
            half = L // 2
            if sum(int(c) for c in st[:half]) == sum(int(c) for c in st[half:]):
                count += 1
        return count

