var countSymmetricIntegers = function(low, high) {
    let count = 0;
    for (let x = low; x <= high; x++) {
        const st = String(x);
        const L = st.length;
        if (L % 2 !== 0) continue;
        const half = L / 2;
        let a = 0, b = 0;
        for (let i = 0; i < half; i++) a += st.charCodeAt(i) - 48;
        for (let i = half; i < L; i++) b += st.charCodeAt(i) - 48;
        if (a === b) count++;
    }
    return count;
};
